public class Example1 {
    /**
     * Two parameters in correct order.
     *
     * @param first the first parameter
     * @param second the second parameter
     */
    public void twoParams(String first, String second) {
    }

    /**
     * Three parameters in correct order.
     *
     * @param first the first parameter
     * @param second the second parameter
     * @param third the third parameter
     */
    public void threeParams(String first, String second, String third) {
    }

    /**
     * Multiple parameters with partial documentation (no violation).
     *
     * @param first the first parameter
     * @param third the third parameter
     */
    public void partialDocs(String first, String second, String third) {
    }
}

public class Example2 {
    /**
     * Two parameters out of order.
     *
     * @param second the second parameter // violation
     * @param first the first parameter   // violation
     */
    public void twoParamsWrong(String first, String second) {
    }

    /**
     * Three parameters out of order.
     *
     * @param third the third parameter   // violation
     * @param first the first parameter   // violation
     * @param second the second parameter // violation
     */
    public void threeParamsWrong(String first, String second, String third) {
    }

    /**
     * Constructor with parameters out of order.
     *
     * @param age the person's age     // violation
     * @param name the person's name   // violation
     */
    public Example2(String name, int age) {
    }
}

public class Example3 {
    /**
     * Single type parameter in correct order.
     *
     * @param <T> the type parameter
     * @param value the value
     */
    public <T> void singleTypeParam(T value) {
    }

    /**
     * Multiple type parameters in correct order.
     *
     * @param <K> the key type
     * @param <V> the value type
     * @param key the key
     * @param value the value
     */
    public <K, V> void multipleTypeParams(K key, V value) {
    }

    /**
     * Type parameter after regular parameter (violation).
     *
     * @param value the value              // violation
     * @param <T> the type parameter      // violation
     */
    public <T> void typeParamWrong(T value) {
    }

    /**
     * Multiple type parameters with regular parameters, correct order.
     *
     * @param <K> the key type
     * @param <V> the value type
     * @param key the key
     * @param value the value
     * @param operation the operation
     */
    public <K, V> void complexMethod(K key, V value, String operation) {
    }
}
